import{c as a,Q as t,j as o,m as l}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Spec-Driven Development with Claude Code in Action","description":"","frontmatter":{"url":"https://alexop.dev/posts/spec-driven-development-claude-code-in-action/","title":"Spec-Driven Development with Claude Code in Action","author":"Alexander Opalic","date":"2026-02-01T00:00:00.000Z","status":"success"},"headers":[],"relativePath":"research/ai-articles/23-alexop-sdd-claude-code.md","filePath":"research/ai-articles/23-alexop-sdd-claude-code.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/23-alexop-sdd-claude-code.md"};function r(d,e,n,s,c,p){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="spec-driven-development-with-claude-code-in-action" tabindex="-1">Spec-Driven Development with Claude Code in Action <a class="header-anchor" href="#spec-driven-development-with-claude-code-in-action" aria-label="Permalink to &quot;Spec-Driven Development with Claude Code in Action&quot;">​</a></h1><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>Alexander Opalic 呈現了一個四階段工作流，用於使用 Claude Code 代理系統管理複雜軟體重構。與其直接深入實作，該方法將 Claude 視為「AI 開發團隊」，人類擔任產品所有者。</p><p>該方法論解決 AI 輔助編碼的兩個關鍵問題：<strong>上下文污染</strong>（累積失敗嘗試填滿上下文窗口）和<strong>代理遺忘</strong>（會話間進度喪失）。Opalic 透過利用 Claude Code 的任務持久化系統解決了此問題，該系統將任務儲存為 <code>.claude/tasks/</code> 中的 JSON 檔案，使工作能在會話重啟中倖存。</p><h2 id="四階段工作流" tabindex="-1">四階段工作流 <a class="header-anchor" href="#四階段工作流" aria-label="Permalink to &quot;四階段工作流&quot;">​</a></h2><p><strong>第一階段：平行研究</strong>產生多個子代理同時調查參考程式碼庫的不同方面。在 Opalic 的 IndexedDB 遷移專案中，五個代理獨立探索 Jazz 框架的架構，報告 CRDT、WebSocket 協議、儲存模式等的發現。</p><p><strong>第二階段：規格建立</strong>將研究整合為綜合技術文件（<code>indexeddb-migration-spec.md</code>）。此規格成為「真實來源」，防止分散實作任務的不一致性。</p><p><strong>第三階段：規格精煉</strong>使用 Claude 的 <code>AskUserQuestion</code> 工具在實作開始前浮現設計歧義。Opalic 質疑衝突解決策略、跨標籤同步方法和 Vue 特定模式。</p><p><strong>第四階段：實作</strong>透過任務委派。主會話擔任協調者，建立生成新鮮子代理上下文的任務。「在每個任務後進行提交再繼續」確保原子、可審查的變更。</p><h2 id="關鍵技術洞察" tabindex="-1">關鍵技術洞察 <a class="header-anchor" href="#關鍵技術洞察" aria-label="Permalink to &quot;關鍵技術洞察&quot;">​</a></h2><p>任務系統的創新在於<strong>依賴性對應</strong>。任務參考 <code>blocks</code> 和 <code>blockedBy</code> 屬性，讓 Claude 識別可平行化的工作。這防止「上下文填滿失敗嘗試」問題，因為每個子代理以清晰記憶啟動。</p><p>Opalic 強調<strong>背壓</strong>：預提交鉤子執行測試和 linting 自動立即捕捉錯誤。「系統驗證正確性，你專注於高層決策」，而非手動審查成為瓶頸。</p><h2 id="可測量結果" tabindex="-1">可測量結果 <a class="header-anchor" href="#可測量結果" aria-label="Permalink to &quot;可測量結果&quot;">​</a></h2><p>SQLite 至 IndexedDB 遷移通常需要 2-3 天手動工作。使用此工作流，Opalic 約 45 分鐘內完成，具有 14 個任務、14 個提交和 15+ 個修改檔案。儘管協調多個子代理，上下文使用仍維持在 71%，證明委派模式的效率。</p><h2 id="何時應用此模式" tabindex="-1">何時應用此模式 <a class="header-anchor" href="#何時應用此模式" aria-label="Permalink to &quot;何時應用此模式&quot;">​</a></h2><p>Opalic 推薦大型重構、遷移、不清楚需求和學習外部程式碼庫的規格驅動開發。它不適合小型錯誤修復或定義明確的單一檔案變更。</p><h2 id="實踐建議" tabindex="-1">實踐建議 <a class="header-anchor" href="#實踐建議" aria-label="Permalink to &quot;實踐建議&quot;">​</a></h2><ol><li><strong>從研究開始</strong>：平行代理調查參考實作發現人類可能遺漏的模式</li><li><strong>編碼前文件化</strong>：寫好的規格倖存會話重啟並指導子代理一致性</li><li><strong>提早詢問利害關係者</strong>：在規格階段澄清歧義，而非實作階段</li><li><strong>原子提交</strong>：每個任務產生一個 git 提交，簡化回滾</li><li><strong>使用背壓</strong>：自動化驗證在來源捕捉問題，而非累積</li></ol><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><ul><li>遷移時間改進：2-3 天 → ~45 分鐘</li><li>任務數：14 個任務</li><li>提交數：14 個提交</li><li>修改檔案數：15+ 檔案</li><li>上下文使用：71%（儘管協調多個子代理）</li><li>子代理數：5 個（平行研究階段）</li></ul><h2 id="核心建議" tabindex="-1">核心建議 <a class="header-anchor" href="#核心建議" aria-label="Permalink to &quot;核心建議&quot;">​</a></h2><p>此工作流鏡像企業軟體工程實踐——平行工作、移交、依賴追蹤和品質閘門。Opalic 將其定位為簡單 AI 提示與完全自主系統（如在無狀態 bash 迴圈中執行的 Ralph）之間的中點。任務系統提供足夠結構以實現一致性，無需完全自主代理的設置開銷。</p><p>該方法從根本上重新構想人類-AI 協作：停止將 Claude 視為獨奏編碼者，改為將其架構為協調團隊，人類管理協調和高階決策。</p>',23)])])}const g=a(i,[["render",r]]);export{u as __pageData,g as default};
